class Solution:
    def countOppositeParity(self, nums):
        n = len(nums)
        ans = []
        for i in range(n):
            cnt = 0
            for j in range(i + 1, n):
                if (nums[i] % 2) != (nums[j] % 2):
                    cnt += 1
            ans.append(cnt)
        return ans

