class Solution:
    def countOppositeParity(self, nums):
        n = len(nums)
        odd_after = 0
        even_after = 0
        ans = [0] * n
        for i in range(n - 1, -1, -1):
            if nums[i] % 2 == 0:
                ans[i] = odd_after
                even_after += 1
            else:
                ans[i] = even_after
                odd_after += 1
        return ans

