var countOppositeParity = function(nums) {
    const n = nums.length;
    const ans = new Array(n).fill(0);
    let oddAfter = 0, evenAfter = 0;
    for (let i = n - 1; i >= 0; i--) {
        if (nums[i] % 2 === 0) {
            ans[i] = oddAfter;
            evenAfter++;
        } else {
            ans[i] = evenAfter;
            oddAfter++;
        }
    }
    return ans;
};
